CREATE SCHEMA IF NOT EXISTS n8n;

CREATE TABLE IF NOT EXISTS n8n.exposes (
  id int4 GENERATED ALWAYS AS IDENTITY( INCREMENT BY 1 MINVALUE 1 MAXVALUE 2147483647 START 1 CACHE 1 NO CYCLE) NOT NULL,
  json_payload json NULL,
  cr_date timestamp DEFAULT now() NULL,
  pdf_hash varchar NULL,
  pdf_data bytea NULL,
  pdf_filename text NULL,
  pdf_mime_type text DEFAULT 'application/pdf'::text NULL,
  pdf_size_bytes int8 NULL,
  CONSTRAINT newtable_pk PRIMARY KEY (id)
);

CREATE INDEX IF NOT EXISTS exposes_pdf_hash_idx ON n8n.exposes (pdf_hash);
CREATE INDEX IF NOT EXISTS exposes_cr_date_idx ON n8n.exposes (cr_date DESC);

SELECT id, json_payload, pdf_hash, pdf_filename, cr_date
FROM n8n.exposes
ORDER BY cr_date DESC LIMIT 5;
